// // This module is designed to capture and store two 32-bit input values (rda and rdb) on the falling edge of a clock signal (clk). The outputs (a and b) reflect the stored values.
module top_module(rda, rdb, a, b, clk);input clk;
	input [31:0] rda, rdb;
	output  [31:0] a, b;
	reg [31:0] a,b;
	always @(posedge clk)
	begin
		 a <= rda;
		 b <= rdb;
	end

endmodule
